xpath.script:

/**
 * ─────────────────────────────────────────────────────────────
 * FUNCIÓN: solicitarCotizacion(element)
 * ─────────────────────────────────────────────────────────────
 * 
 * Gestiona la solicitud de cotización desde tarjetas de producto.
 * (Se ejecuta cuando haces click en el botón en /shop)
 * 
 * COMPORTAMIENTO ACTUAL:
 * - Muestra una alerta con el nombre del producto
 * - Redirige al bot de Martín cuando tengas el nº de WhatsApp
 * 
 * CONFIGURACIÓN PENDIENTE:
 * 1. Reemplaza MARTIN_WHATSAPP_NUMBER con el número real
 * 2. Descomenta window.open(urlBot, '_blank')
 */
function solicitarCotizacion(element) {
    // ─────────────────────────────────────────────────────
    // OBTENER DATOS DEL PRODUCTO
    // ─────────────────────────────────────────────────────
    const productName = element.getAttribute('data-product-name');
    const productId = element.getAttribute('data-product-id');

    // ─────────────────────────────────────────────────────
    // CONFIGURACIÓN: Número de WhatsApp de Martín
    // ─────────────────────────────────────────────────────
    // TODO: Reemplazar "" con el número de Martín
    // Formato: "34666666666" (código país + número sin +)
    const MARTIN_WHATSAPP_NUMBER = "";

    // ─────────────────────────────────────────────────────
    // CONSTRUIR MENSAJE Y URL
    // ─────────────────────────────────────────────────────
    const mensaje = `Hola, estoy interesado en la siguiente cotización:\n\n` +
                   `Producto: ${productName}\n\n` +
                   `Me gustaría recibir más información.`;

    const urlBot = 'https://api.whatsapp.com/send/?phone=' + MARTIN_WHATSAPP_NUMBER + 
                   '&text=' + encodeURIComponent(mensaje);

    // ─────────────────────────────────────────────────────
    // COMPORTAMIENTO TEMPORAL (sin número de WhatsApp)
    // ─────────────────────────────────────────────────────
    if (MARTIN_WHATSAPP_NUMBER === "") {
        // Mostrar alerta temporal 
        alert('📋 Solicitud de cotización recibida:\n\n' +
              '✅ Producto: ' + productName + '\n\n' +
              '⏳ Cuando tengas el número de Martín, ' +
              'serás redirigido automáticamente a WhatsApp');
    } else {
        // Cuando tengas el número, abre WhatsApp directamente
        // TODO: Descomentar esta línea
        // window.open(urlBot, '_blank');
    }
}

/**
 * ─────────────────────────────────────────────────────────────
 * FUNCIÓN: solicitarCotizacionDetail(event)
 * ─────────────────────────────────────────────────────────────
 * 
 * Gestiona la solicitud de cotización desde página de detalles.
 * (Se ejecuta cuando haces click en el botón en /shop/producto-xxx)
 * 
 * Similar a solicitarCotizacion() pero optimizada para la página
 * de detalles donde el producto ya está cargado en el DOM.
 */
function solicitarCotizacionDetail(event) {
    // Prevenir el comportamiento por defecto del link
    event.preventDefault();

    // ─────────────────────────────────────────────────────
    // OBTENER DATOS DEL PRODUCTO DESDE EL BOTÓN
    // ─────────────────────────────────────────────────────
    const button = event.currentTarget;
    const productName = button.getAttribute('data-product-name');
    const productId = button.getAttribute('data-product-id');

    // ─────────────────────────────────────────────────────
    // CONFIGURACIÓN: Número de WhatsApp de Martín
    // ─────────────────────────────────────────────────────
    // TODO: Reemplazar "" con el número de Martín
    // Formato: "34666666666" (código país + número sin +)
    const MARTIN_WHATSAPP_NUMBER = "";

    // ─────────────────────────────────────────────────────
    // CONSTRUIR MENSAJE Y URL
    // ─────────────────────────────────────────────────────
    const mensaje = `Hola, estoy interesado en la siguiente cotización:\n\n` +
                   `Producto: ${productName}\n\n` +
                   `Me gustaría recibir más información.`;

    const urlBot = 'https://api.whatsapp.com/send/?phone=' + MARTIN_WHATSAPP_NUMBER + 
                   '&text=' + encodeURIComponent(mensaje);

    // ─────────────────────────────────────────────────────
    // COMPORTAMIENTO TEMPORAL (sin número de WhatsApp)
    // ─────────────────────────────────────────────────────
    if (MARTIN_WHATSAPP_NUMBER === "") {
        // Mostrar alerta temporal 
        alert('📋 Solicitud de cotización recibida:\n\n' +
              '✅ Producto: ' + productName + '\n\n' +
              '⏳ Cuando tengas el número de Martín, ' +
              'serás redirigido automáticamente a WhatsApp');
    } else {
        // Cuando tengas el número, abre WhatsApp directamente
        // TODO: Descomentar esta línea
        // window.open(urlBot, '_blank');
    }

    // Retornar false para evitar comportamiento del link
    return false;
}
